def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a * 2):
                    power = (ratio - a) ** 6 / (a * b + 1.1)
                    trig = np.sin(ratio * b / (a + 2)) * np.cos(ratio / (b + 0.5))
                    priority += power * trig * np.tanh(a + b)
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2 + np.log1p(item + bin_cap) * 3
        elif 5 < ratio <= 8:
            for x in range(3, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 5):
                    term = ((ratio - x) ** 4) * np.cos(ratio * y) / (y ** 1.5 + 1)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 20):
                s += ((ratio - 2) ** r) / (r * 2) * np.cos(r * ratio * 0.75)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 5 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 <= ratio < 2:
            s1 = 0
            for n in range(1, 15):
                s1 += ((2 - ratio) ** n) / (n ** 2 + 1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s1 + penalty + np.exp(-1.3 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.7) * ((ratio - 1) ** m) / (m ** 1.1)
        elif 0.5 <= ratio < 1:
            s2 = 0
            for n in range(1, 25):
                s2 += ((1 - ratio) ** n) / (n * 3.5)
            priority = s2
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s3 = 0
            for k in range(1, 15):
                s3 += ((0.5 - ratio) ** k) / (k * 4.5) * np.cos(k * ratio * 2.5)
            priority = s3 + 2 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s4 = 0
            for t in range(1, 15):
                s4 += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s4 + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if i % 5 == 0 and bin_cap > item:
            for z in range(1, 5):
                priority += np.sin(z * ratio * i) / (z * 2)
        else:
            for z in range(1, 5):
                priority -= np.cos(z * ratio * i) / (z * 2)
        priorities[i] = priority
    return priorities
